'use client'
import { useEffect, useRef, useState } from 'react'

const NSUT_B64 = ''
const DTU_B64 = ''
const IITD_B64 = ''
const IITKGP_B64 = ''

const LOGOS = [
  { name: 'NSUT', full: 'Netaji Subhas University of Technology', b64: NSUT_B64, color: '#cc0000', x: 7, y: 18, z: 0, size: 92, delay: 0 },
  { name: 'DTU', full: 'Delhi Technological University', b64: DTU_B64, color: '#1a1a2e', x: 80, y: 12, z: -50, size: 82, delay: 0.5 },
  { name: 'IIT Delhi', full: 'Indian Institute of Technology Delhi', b64: IITD_B64, color: '#cc0000', x: 74, y: 62, z: -30, size: 86, delay: 0.9 },
  { name: 'IIT KGP', full: 'IIT Kharagpur', b64: IITKGP_B64, color: '#1a3a6b', x: 12, y: 66, z: -70, size: 76, delay: 1.3 },
]

export default function FloatingLogos() {
  const [mouse, setMouse] = useState({ x: 0, y: 0 })
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    setMounted(true)
    const handleMouse = (e) => {
      const x = (e.clientX / window.innerWidth - 0.5) * 2
      const y = (e.clientY / window.innerHeight - 0.5) * 2
      setMouse({ x, y })
    }
    window.addEventListener('mousemove', handleMouse)
    return () => window.removeEventListener('mousemove', handleMouse)
  }, [])

  if (!mounted) return null

  return (
    <div style={{
      position: 'absolute', inset: 0, zIndex: 1,
      pointerEvents: 'none', overflow: 'hidden',
      perspective: '900px',
    }}>
      {LOGOS.map((logo, i) => {
        const parallaxX = mouse.x * (18 + i * 7)
        const parallaxY = mouse.y * (12 + i * 5)
        const blurAmt = Math.abs(logo.z) / 90 * 1.2
        const opacityVal = 0.85 - Math.abs(logo.z) / 300

        return (
          <div
            key={logo.name}
            className={`logo-float-${i}`}
            style={{
              position: 'absolute',
              left: logo.x + '%',
              top: logo.y + '%',
              transform: `translate(${parallaxX}px, ${parallaxY}px) translateZ(${logo.z}px)`,
              transition: 'transform 0.12s ease-out',
              animationDelay: logo.delay + 's',
            }}
          >
            <div style={{
              display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 8,
              filter: blurAmt > 0 ? `blur(${blurAmt}px)` : 'none',
              opacity: opacityVal,
            }}>
              {/* Outer glow */}
              <div style={{
                position: 'relative',
                width: logo.size + 20,
                height: logo.size + 20,
                borderRadius: '50%',
                background: `radial-gradient(circle, ${logo.color}15 0%, transparent 70%)`,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                boxShadow: `0 0 40px ${logo.color}20, 0 0 80px ${logo.color}0a`,
              }}>
                {/* Logo */}
                <img
                  src={'data:image/png;base64,' + logo.b64}
                  alt={logo.name}
                  style={{
                    width: logo.size,
                    height: logo.size,
                    borderRadius: '50%',
                    objectFit: 'contain',
                    background: 'rgba(255,255,255,0.88)',
                    boxShadow: '0 10px 40px rgba(0,0,0,0.14), 0 4px 12px rgba(0,0,0,0.08)',
                    border: '3px solid rgba(255,255,255,0.95)',
                    padding: 7,
                  }}
                />
                {/* Shine */}
                <div style={{
                  position: 'absolute', inset: 0, borderRadius: '50%',
                  background: 'linear-gradient(135deg, rgba(255,255,255,0.3) 0%, transparent 55%)',
                  pointerEvents: 'none',
                }} />
              </div>
              {/* Badge */}
              <div style={{
                background: 'rgba(255,255,255,0.78)',
                backdropFilter: 'blur(10px)',
                border: '1px solid rgba(255,200,220,0.55)',
                borderRadius: 100,
                padding: '4px 13px',
                fontSize: 11,
                fontWeight: 600,
                color: logo.color,
                fontFamily: 'DM Sans, sans-serif',
                letterSpacing: '0.05em',
                boxShadow: '0 2px 12px rgba(212,84,122,0.1)',
                whiteSpace: 'nowrap',
              }}>{logo.name}</div>
            </div>
          </div>
        )
      })}

      <style>{`
        .logo-float-0 { animation: lf0 5.5s ease-in-out infinite; }
        .logo-float-1 { animation: lf1 6.2s ease-in-out infinite; }
        .logo-float-2 { animation: lf2 5.8s ease-in-out infinite; }
        .logo-float-3 { animation: lf3 6.8s ease-in-out infinite; }

        @keyframes lf0 {
          0%, 100% { transform: translateY(0px) rotate(0deg); }
          35% { transform: translateY(-20px) rotate(1.5deg); }
          65% { transform: translateY(-9px) rotate(-0.8deg); }
        }
        @keyframes lf1 {
          0%, 100% { transform: translateY(0px) rotate(0deg); }
          40% { transform: translateY(-24px) rotate(-1.8deg); }
          70% { transform: translateY(-11px) rotate(1.2deg); }
        }
        @keyframes lf2 {
          0%, 100% { transform: translateY(0px) rotate(0deg); }
          30% { transform: translateY(-15px) rotate(1.2deg); }
          60% { transform: translateY(-22px) rotate(-1.3deg); }
        }
        @keyframes lf3 {
          0%, 100% { transform: translateY(0px) rotate(0deg); }
          45% { transform: translateY(-18px) rotate(-1deg); }
          75% { transform: translateY(-26px) rotate(1.5deg); }
        }
      `}</style>
    </div>
  )
}
